/**
 * @summary Get recent logs for an app
 */
export const getGetAppLogsUrl = (id: string, params?: GetAppLogsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/apps/${id}/logs?${stringifiedParams}`
    : `/api/apps/${id}/logs`;
};

export const getAppLogs = async (
  id: string,
  params?: GetAppLogsParams,
  options?: RequestInit,
): Promise<LogEntry[]> => {
  return customFetch<LogEntry[]>(getGetAppLogsUrl(id, params), {
    ...options,
    method: "GET",
  });
};

export const getGetAppLogsQueryKey = (
  id: string,
  params?: GetAppLogsParams,
) => {
  return [`/api/apps/${id}/logs`, ...(params ? [params] : [])] as const;
};

export const getGetAppLogsQueryOptions = <
  TData = Awaited<ReturnType<typeof getAppLogs>>,
  TError = ErrorType<ErrorResponse>,
>(
  id: string,
  params?: GetAppLogsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getAppLogs>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetAppLogsQueryKey(id, params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getAppLogs>>> = ({
    signal,
  }) => getAppLogs(id, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!id,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getAppLogs>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetAppLogsQueryResult = NonNullable<
  Awaited<ReturnType<typeof getAppLogs>>
>;
export type GetAppLogsQueryError = ErrorType<ErrorResponse>;

/**
 * @summary Get recent logs for an app
 */

export function useGetAppLogs<
  TData = Awaited<ReturnType<typeof getAppLogs>>,
  TError = ErrorType<ErrorResponse>,
>(
  id: string,
  params?: GetAppLogsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getAppLogs>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetAppLogsQueryOptions(id, params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
